import{_ as a,o as d,c as l,a2 as r}from"./chunks/framework.Bjylvv1V.js";const b=JSON.parse('{"title":"단지 초기 설정","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/site-setup.md","filePath":"guide/scenarios/site-setup.md","lastUpdated":null}'),e={name:"guide/scenarios/site-setup.md"};function o(i,t,n,s,h,c){return d(),l("div",null,[...t[0]||(t[0]=[r(`<h1 id="단지-초기-설정" tabindex="-1">단지 초기 설정 <a class="header-anchor" href="#단지-초기-설정" aria-label="Permalink to &quot;단지 초기 설정&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 3시간 | <strong>난이도</strong>: ★★★ | <strong>주기</strong>: 최초 1회 (신규 단지)</p></blockquote><p>XpERP를 처음 사용하는 단지에서 시스템 운영에 필요한 기초 정보를 등록하는 프로세스입니다. 이 설정이 모든 업무의 토대가 됩니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1.  단지정보등록         (15분) → 단지코드·명칭·주소·사업자 정보</span></span>
<span class="line"><span>2.  동호생성             (30분) → 동별 라인·호수·층수·면적 구성</span></span>
<span class="line"><span>3.  공동동호관리         (10분) → 임의 동호 추가 (선택)</span></span>
<span class="line"><span>4.  세대검침환경등록     (20분) → 세대별 검침 항목 설정</span></span>
<span class="line"><span>5.  환경설정             (30분) → 검침·부과·고지서·할인 환경</span></span>
<span class="line"><span>6.  조견표 등록          (20분) → 관리비·주차비 조견표</span></span>
<span class="line"><span>7.  입주자단체등록       (10분) → 입주자대표회의 등 단체 정보</span></span>
<span class="line"><span>8.  결재라인등록         (15분) → 장표별 결재 경로 설정</span></span>
<span class="line"><span>9.  연말정산기본정보등록 (10분) → 급여 관련 공제 정보</span></span>
<span class="line"><span>10. 모바일발송 설정      (15분) → 발신번호 인증·SMS/카카오 연동</span></span></code></pre></div><hr><div class="danger custom-block"><p class="custom-block-title">단지코드는 수정 불가</p><p>단지코드는 <strong>최초 등록 후 절대 수정할 수 없습니다.</strong> 단지코드를 잘못 등록하면 모든 정보를 처음부터 다시 등록해야 합니다. 입력 전에 반드시 확인하세요.</p></div><hr><h2 id="_1단계-단지정보등록-15분" tabindex="-1">1단계: 단지정보등록 (15분) <a class="header-anchor" href="#_1단계-단지정보등록-15분" aria-label="Permalink to &quot;1단계: 단지정보등록 (15분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 단지관리 &gt; <a href="/dang/dang-info.html">단지정보</a> &gt; 단지정보등록 (DANG0010)</p></blockquote><p>단지의 기본 정보를 등록합니다. 모든 업무의 기준이 되는 첫 번째 설정입니다.</p><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>단지정보등록 화면 진입</li><li>다음 항목 입력:</li></ol><table tabindex="0"><thead><tr><th>항목</th><th>설명</th><th>주의</th></tr></thead><tbody><tr><td><strong>단지코드</strong></td><td>시스템 내 고유 식별 코드</td><td><strong>등록 후 수정 불가</strong></td></tr><tr><td>단지명</td><td>아파트 공식 명칭</td><td></td></tr><tr><td>주소</td><td>단지 도로명 주소</td><td></td></tr><tr><td>세대수</td><td>총 세대 수</td><td></td></tr><tr><td>사업자등록번호</td><td>관리소 사업자등록번호</td><td></td></tr><tr><td>대표자명</td><td>관리소장 성명</td><td></td></tr><tr><td>업태/종목</td><td>부동산 / 아파트관리</td><td></td></tr></tbody></table><ol start="3"><li><strong>저장</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">사업자 정보 정확히 입력</p><p>사업자등록번호·대표자명 등은 세금계산서, 원천징수 신고 등에 사용됩니다. 관할 세무서에 등록된 정보와 정확히 일치해야 합니다.</p></div><hr><h2 id="_2단계-동호생성-30분" tabindex="-1">2단계: 동호생성 (30분) <a class="header-anchor" href="#_2단계-동호생성-30분" aria-label="Permalink to &quot;2단계: 동호생성 (30분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 단지관리 &gt; <a href="/dang/dang-info.html">단지정보</a> &gt; 동호생성 (DANG0030)</p></blockquote><p>단지의 동·호수 구조를 생성합니다. 검침, 부과, 입주자 관리 등 모든 세대별 업무의 기준이 됩니다.</p><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>동호생성 화면 진입</li><li>동 정보 입력: <ul><li>동 번호 (예: 101동, 102동)</li><li>지하 층수</li><li>지상 층수</li><li>층당 세대 수 (라인 수)</li></ul></li><li><strong>동라인생성</strong> 버튼 클릭: <ul><li>승강기 라인 지정</li><li>라인별 순서 설정 (호수 부여 기준)</li></ul></li><li>면적 정보 입력: <ul><li>세대별 전용면적</li><li>공용면적 (비례 배분 기준)</li></ul></li><li>생성 결과 확인 후 <strong>저장</strong></li></ol><h3 id="확인-포인트" tabindex="-1">확인 포인트 <a class="header-anchor" href="#확인-포인트" aria-label="Permalink to &quot;확인 포인트&quot;">​</a></h3><ul><li>[ ] 동 수와 실제 건물 수가 일치하는가?</li><li>[ ] 각 동의 층수가 정확한가?</li><li>[ ] 호수 부여 방식이 실제 단지와 동일한가? (예: 라인별 순서)</li><li>[ ] 면적 정보가 건축물 대장과 일치하는가?</li></ul><div class="warning custom-block"><p class="custom-block-title">동·호수 변경 제한</p><p>동·호수 정보는 입주자 정보와 연결됩니다. 등록 후 변경하려면 해당 세대의 <strong>전출 처리를 완료한 후</strong>에만 삭제·수정할 수 있습니다. 초기 등록 시 신중하게 입력하세요.</p></div><hr><h2 id="_3단계-공동동호관리-10분-선택" tabindex="-1">3단계: 공동동호관리 (10분, 선택) <a class="header-anchor" href="#_3단계-공동동호관리-10분-선택" aria-label="Permalink to &quot;3단계: 공동동호관리 (10분, 선택)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 단지관리 &gt; <a href="/dang/dang-info.html">단지정보</a> &gt; 공동동호관리 (DANG0036)</p></blockquote><p>관리사무소, 경비실, 노인정 등 일반적인 동호 생성으로 만들 수 없는 임의 동호를 추가 등록합니다.</p><h3 id="사용-예시" tabindex="-1">사용 예시 <a class="header-anchor" href="#사용-예시" aria-label="Permalink to &quot;사용 예시&quot;">​</a></h3><table tabindex="0"><thead><tr><th>용도</th><th>임의 동호 예시</th></tr></thead><tbody><tr><td>관리사무소</td><td>000동 000호</td></tr><tr><td>경비실</td><td>경비동 01호</td></tr><tr><td>공용 시설</td><td>노인정, 커뮤니티센터</td></tr><tr><td>상가</td><td>상가동 101호</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">공동동호 활용</p><p>공동동호를 등록하면 관리사무소·상가 등에도 관리비 부과 및 검침 관리가 가능합니다.</p></div><hr><h2 id="_4단계-세대검침환경등록-20분" tabindex="-1">4단계: 세대검침환경등록 (20분) <a class="header-anchor" href="#_4단계-세대검침환경등록-20분" aria-label="Permalink to &quot;4단계: 세대검침환경등록 (20분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 단지관리 &gt; <a href="/dang/dang-info.html">단지정보</a> &gt; 세대검침환경등록 (DANG0035)</p></blockquote><p>세대별로 검침이 필요한 항목(전기, 수도, 온수, 가스, 난방 등)을 설정합니다.</p><h3 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>세대검침환경등록 화면 진입</li><li>세대별로 각 검침 항목 설정:</li></ol><table tabindex="0"><thead><tr><th>검침 항목</th><th>설정값</th><th>설명</th></tr></thead><tbody><tr><td>전기</td><td>Y / N</td><td>개별 전기계량기 보유 여부</td></tr><tr><td>수도</td><td>Y / N</td><td>개별 수도계량기 보유 여부</td></tr><tr><td>온수</td><td>Y / N</td><td>온수 계량기 보유 여부</td></tr><tr><td>가스</td><td>Y / N</td><td>개별 가스계량기 보유 여부</td></tr><tr><td>난방</td><td>Y / N</td><td>개별 난방계량기 보유 여부</td></tr><tr><td>정수</td><td>Y / N</td><td>정수기 계량기 보유 여부</td></tr></tbody></table><ol start="3"><li><strong>계량기 자리수</strong> 설정 (계량기 표시 최대 자릿수)</li><li>저장</li></ol><div class="danger custom-block"><p class="custom-block-title">검침환경 누락 주의</p><p>특정 세대에 검침환경이 등록되지 않으면 해당 검침 항목이 <strong>검침 화면에 표시되지 않습니다.</strong> 검침 누락이 발생하면 관리비 부과 오류로 이어집니다.</p></div><h3 id="대량-설정-방법" tabindex="-1">대량 설정 방법 <a class="header-anchor" href="#대량-설정-방법" aria-label="Permalink to &quot;대량 설정 방법&quot;">​</a></h3><p>세대 수가 많은 경우 엑셀 업로드로 일괄 등록할 수 있습니다.</p><ul><li>엑셀 양식 다운로드 → 항목 입력 → 업로드 실행</li><li>파일 형식: <strong>Excel 97-2003(.xls)</strong></li></ul><hr><h2 id="_5단계-환경설정-30분" tabindex="-1">5단계: 환경설정 (30분) <a class="header-anchor" href="#_5단계-환경설정-30분" aria-label="Permalink to &quot;5단계: 환경설정 (30분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 단지관리 &gt; <a href="/dang/dang-env.html">환경설정</a></p></blockquote><p>단지 운영에 필요한 각종 환경을 설정합니다.</p><h3 id="검침환경-dang-env-검침" tabindex="-1">검침환경 (DANG-ENV-검침) <a class="header-anchor" href="#검침환경-dang-env-검침" aria-label="Permalink to &quot;검침환경 (DANG-ENV-검침)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>설정 항목</th><th>내용</th></tr></thead><tbody><tr><td>검침 주기</td><td>월 검침 또는 격월 검침</td></tr><tr><td>검침 방법</td><td>직접 검침 / 원격 검침</td></tr><tr><td>검침일</td><td>월 검침 기준일</td></tr></tbody></table><h3 id="부과환경-dang-env-부과" tabindex="-1">부과환경 (DANG-ENV-부과) <a class="header-anchor" href="#부과환경-dang-env-부과" aria-label="Permalink to &quot;부과환경 (DANG-ENV-부과)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>설정 항목</th><th>내용</th></tr></thead><tbody><tr><td>부과 기준</td><td>면적 기준 / 세대 기준 / 혼합</td></tr><tr><td>납부 기한</td><td>당월 말 / 익월 말 등</td></tr><tr><td>연체 가산금</td><td>연체료율 및 적용 기준</td></tr></tbody></table><h3 id="고지서인쇄환경" tabindex="-1">고지서인쇄환경 <a class="header-anchor" href="#고지서인쇄환경" aria-label="Permalink to &quot;고지서인쇄환경&quot;">​</a></h3><table tabindex="0"><thead><tr><th>설정 항목</th><th>내용</th></tr></thead><tbody><tr><td>고지서 양식</td><td>단지 맞춤 양식 선택</td></tr><tr><td>인쇄 항목</td><td>고지서에 표시할 항목 선택</td></tr><tr><td>은행 가상계좌</td><td>수납 계좌 정보</td></tr></tbody></table><h3 id="단지검침환경" tabindex="-1">단지검침환경 <a class="header-anchor" href="#단지검침환경" aria-label="Permalink to &quot;단지검침환경&quot;">​</a></h3><p>단지 전체의 공용 검침 방식 및 기준을 설정합니다.</p><h3 id="할인항목" tabindex="-1">할인항목 <a class="header-anchor" href="#할인항목" aria-label="Permalink to &quot;할인항목&quot;">​</a></h3><p>경로 우대, 장애인 할인 등 관리비 감면 항목을 설정합니다.</p><table tabindex="0"><thead><tr><th>할인 유형</th><th>설명</th></tr></thead><tbody><tr><td>경로우대</td><td>만 65세 이상 세대주</td></tr><tr><td>장애인</td><td>장애 등급에 따라 적용</td></tr><tr><td>국가유공자</td><td>관련 법령 기준</td></tr></tbody></table><hr><h2 id="_6단계-조견표-등록-20분" tabindex="-1">6단계: 조견표 등록 (20분) <a class="header-anchor" href="#_6단계-조견표-등록-20분" aria-label="Permalink to &quot;6단계: 조견표 등록 (20분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 단지관리 &gt; <a href="/dang/dang-table.html">조견표</a></p></blockquote><p>관리비 및 주차비 산정에 사용하는 단가 기준표를 등록합니다.</p><h3 id="관리비-조견표" tabindex="-1">관리비 조견표 <a class="header-anchor" href="#관리비-조견표" aria-label="Permalink to &quot;관리비 조견표&quot;">​</a></h3><p>검침량에 따른 요금 계산 기준을 등록합니다.</p><table tabindex="0"><thead><tr><th>항목</th><th>설정 내용</th></tr></thead><tbody><tr><td>전기 요금</td><td>구간별 단가 (한전 기준)</td></tr><tr><td>수도 요금</td><td>구간별 단가 (지자체 기준)</td></tr><tr><td>가스 요금</td><td>구간별 단가 (도시가스 기준)</td></tr><tr><td>난방 요금</td><td>구간별 단가</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">요금 기준 변경 시</p><p>공공요금 인상 등으로 단가가 변경될 때 조견표를 업데이트하세요. 변경 전·후 내역이 모두 기록됩니다.</p></div><h3 id="주차비-조견표" tabindex="-1">주차비 조견표 <a class="header-anchor" href="#주차비-조견표" aria-label="Permalink to &quot;주차비 조견표&quot;">​</a></h3><p>차량 등록 수, 주차 구역, 시간 기준 등에 따른 주차비 단가를 설정합니다.</p><table tabindex="0"><thead><tr><th>구분</th><th>예시</th></tr></thead><tbody><tr><td>1대 등록 세대</td><td>기본 주차비</td></tr><tr><td>2대 이상 등록</td><td>추가 차량 할증</td></tr><tr><td>미등록 차량</td><td>일일 주차료</td></tr></tbody></table><hr><h2 id="_7단계-입주자단체등록-10분" tabindex="-1">7단계: 입주자단체등록 (10분) <a class="header-anchor" href="#_7단계-입주자단체등록-10분" aria-label="Permalink to &quot;7단계: 입주자단체등록 (10분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 단지관리 &gt; <a href="/dang/dang-info.html">단지정보</a> &gt; 입주자단체등록 (DANG0020)</p></blockquote><p>단지 내 입주자 관련 단체를 등록합니다.</p><h3 id="주요-등록-단체" tabindex="-1">주요 등록 단체 <a class="header-anchor" href="#주요-등록-단체" aria-label="Permalink to &quot;주요 등록 단체&quot;">​</a></h3><table tabindex="0"><thead><tr><th>단체명</th><th>설명</th></tr></thead><tbody><tr><td>입주자대표회의</td><td>단지 최고 의결 기관</td></tr><tr><td>선거관리위원회</td><td>대표회의 선거 관리</td></tr><tr><td>자생단체</td><td>노인회, 부녀회 등</td></tr></tbody></table><h3 id="입력-항목" tabindex="-1">입력 항목 <a class="header-anchor" href="#입력-항목" aria-label="Permalink to &quot;입력 항목&quot;">​</a></h3><ul><li>단체명</li><li>구성원 정보 (대표자, 임원)</li><li>연락처</li><li>임기</li></ul><hr><h2 id="_8단계-결재라인등록-15분" tabindex="-1">8단계: 결재라인등록 (15분) <a class="header-anchor" href="#_8단계-결재라인등록-15분" aria-label="Permalink to &quot;8단계: 결재라인등록 (15분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 단지관리 &gt; <a href="/dang/dang-info.html">단지정보</a> &gt; 결재라인등록 (DANG0051)</p></blockquote><p>전표, 공문, 지출결의서 등 각 장표별 결재 경로를 설정합니다.</p><h3 id="절차-3" tabindex="-1">절차 <a class="header-anchor" href="#절차-3" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>결재라인등록 화면 진입</li><li>장표 종류 선택 (예: 지출결의서, 공문, 이체결의서)</li><li>결재 단계 설정: <ul><li>기안자 → 검토자 → 결재자 순서로 지정</li><li>대리 결재자 지정 (부재 시)</li></ul></li><li>저장</li></ol><h3 id="설정-예시" tabindex="-1">설정 예시 <a class="header-anchor" href="#설정-예시" aria-label="Permalink to &quot;설정 예시&quot;">​</a></h3><table tabindex="0"><thead><tr><th>장표</th><th>결재 단계</th></tr></thead><tbody><tr><td>지출결의서</td><td>담당 → 팀장 → 관리소장</td></tr><tr><td>이체결의서</td><td>담당 → 관리소장 → 입대의 대표</td></tr><tr><td>공문</td><td>담당 → 관리소장</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">결재라인 미설정 시</p><p>결재라인이 등록되지 않은 장표는 결재 요청이 불가합니다. 아파트뱅크 이체 등 결재가 필요한 업무 전에 반드시 설정하세요.</p></div><hr><h2 id="_9단계-연말정산기본정보등록-10분" tabindex="-1">9단계: 연말정산기본정보등록 (10분) <a class="header-anchor" href="#_9단계-연말정산기본정보등록-10분" aria-label="Permalink to &quot;9단계: 연말정산기본정보등록 (10분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 단지관리 &gt; <a href="/dang/dang-info.html">단지정보</a> &gt; 연말정산기본정보등록 (DANG0170)</p></blockquote><p>직원 급여의 연말정산에 필요한 기본 정보를 등록합니다.</p><h3 id="입력-항목-1" tabindex="-1">입력 항목 <a class="header-anchor" href="#입력-항목-1" aria-label="Permalink to &quot;입력 항목&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>귀속 연도</td><td>정산 기준 연도</td></tr><tr><td>사업자등록번호</td><td>관리소 사업자번호</td></tr><tr><td>세액 계산 기준</td><td>간이세액표 기준 설정</td></tr><tr><td>비과세 항목</td><td>식대, 차량유지비 등 비과세 한도</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">연도별 갱신</p><p>연말정산기본정보는 <strong>매년 초</strong> 해당 귀속 연도로 갱신해야 합니다. 세법 개정에 따라 비과세 한도 등이 변경될 수 있으니 국세청 기준을 확인하세요.</p></div><hr><h2 id="_10단계-모바일발송-설정-15분" tabindex="-1">10단계: 모바일발송 설정 (15분) <a class="header-anchor" href="#_10단계-모바일발송-설정-15분" aria-label="Permalink to &quot;10단계: 모바일발송 설정 (15분)&quot;">​</a></h2><p>고지서·안내문 등을 SMS 또는 카카오 알림톡으로 발송하기 위한 설정입니다.</p><h3 id="발신번호-인증-절차" tabindex="-1">발신번호 인증 절차 <a class="header-anchor" href="#발신번호-인증-절차" aria-label="Permalink to &quot;발신번호 인증 절차&quot;">​</a></h3><p>모바일 발송을 사용하려면 <strong>발신번호 인증</strong>이 필수입니다. 아래 순서대로 진행하세요.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 통신가입증명서 발급  → 관리소 명의 통신사 방문 발급</span></span>
<span class="line"><span>2. 발신번호 대리인      → 대리인 신청서 작성 (관리소장 서명)</span></span>
<span class="line"><span>   신청서 작성</span></span>
<span class="line"><span>3. 서류 전산업체 제출   → 담당 전산업체에 서류 이메일/팩스 발송</span></span>
<span class="line"><span>4. 등록 완료 확인       → 업체로부터 등록 완료 통보 후 사용 가능</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">발신번호 미인증 시 발송 불가</p><p>통신법 개정으로 인증되지 않은 번호로는 단체 문자 발송이 불가합니다. 반드시 인증 절차를 완료한 후 발송하세요.</p></div><h3 id="sms-카카오-환경-설정" tabindex="-1">SMS / 카카오 환경 설정 <a class="header-anchor" href="#sms-카카오-환경-설정" aria-label="Permalink to &quot;SMS / 카카오 환경 설정&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>발신번호</td><td>인증 완료된 전화번호 입력</td></tr><tr><td>SMS 기본 메시지</td><td>고지서 발송 기본 문구 설정</td></tr><tr><td>카카오 채널</td><td>카카오 비즈니스 채널 연동</td></tr><tr><td>발송 시점</td><td>자동 발송 기준 설정</td></tr></tbody></table><hr><h2 id="초기-설정-완료-체크리스트" tabindex="-1">초기 설정 완료 체크리스트 <a class="header-anchor" href="#초기-설정-완료-체크리스트" aria-label="Permalink to &quot;초기 설정 완료 체크리스트&quot;">​</a></h2><p>모든 단계를 완료한 후 아래를 점검하세요.</p><h3 id="기본-구조" tabindex="-1">기본 구조 <a class="header-anchor" href="#기본-구조" aria-label="Permalink to &quot;기본 구조&quot;">​</a></h3><ul><li>[ ] 단지코드가 올바르게 등록되었는가?</li><li>[ ] 모든 동·호수가 정확하게 생성되었는가?</li><li>[ ] 세대별 면적 정보가 건축물 대장과 일치하는가?</li><li>[ ] 각 세대의 검침 항목이 모두 설정되었는가?</li></ul><h3 id="환경-및-단가" tabindex="-1">환경 및 단가 <a class="header-anchor" href="#환경-및-단가" aria-label="Permalink to &quot;환경 및 단가&quot;">​</a></h3><ul><li>[ ] 검침·부과·고지서 환경이 설정되었는가?</li><li>[ ] 관리비·주차비 조견표가 등록되었는가?</li><li>[ ] 할인 항목이 설정되었는가?</li></ul><h3 id="운영-준비" tabindex="-1">운영 준비 <a class="header-anchor" href="#운영-준비" aria-label="Permalink to &quot;운영 준비&quot;">​</a></h3><ul><li>[ ] 입주자대표회의 정보가 등록되었는가?</li><li>[ ] 결재라인이 모든 장표에 설정되었는가?</li><li>[ ] 연말정산기본정보가 등록되었는가?</li><li>[ ] 모바일 발신번호 인증이 완료되었는가?</li></ul><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="단지코드를-잘못-입력했어요" tabindex="-1">단지코드를 잘못 입력했어요 <a class="header-anchor" href="#단지코드를-잘못-입력했어요" aria-label="Permalink to &quot;단지코드를 잘못 입력했어요&quot;">​</a></h3><p><strong>원인</strong>: 단지코드는 등록 후 수정이 불가합니다. <strong>해결</strong>: 모든 데이터를 삭제하고 처음부터 재등록해야 합니다. <strong>저장 전에 반드시 재확인</strong>하세요. 의문이 있으면 전산업체에 문의하세요.</p><h3 id="동호를-생성했는데-검침-화면에-세대가-안-나와요" tabindex="-1">동호를 생성했는데 검침 화면에 세대가 안 나와요 <a class="header-anchor" href="#동호를-생성했는데-검침-화면에-세대가-안-나와요" aria-label="Permalink to &quot;동호를 생성했는데 검침 화면에 세대가 안 나와요&quot;">​</a></h3><p><strong>원인</strong>: 세대검침환경등록(DANG0035)에서 해당 세대의 검침 항목이 설정되지 않은 경우 <strong>해결</strong>: 세대검침환경등록 화면에서 해당 세대를 찾아 필요한 검침 항목을 Y로 설정하세요.</p><h3 id="면적을-잘못-입력했는데-수정할-수-있나요" tabindex="-1">면적을 잘못 입력했는데 수정할 수 있나요? <a class="header-anchor" href="#면적을-잘못-입력했는데-수정할-수-있나요" aria-label="Permalink to &quot;면적을 잘못 입력했는데 수정할 수 있나요?&quot;">​</a></h3><p><strong>원인</strong>: 입주자가 없는 세대(미입주)는 수정 가능하지만, 입주 처리된 세대는 전출 처리 후에만 변경할 수 있습니다. <strong>해결</strong>: 입주 전이라면 즉시 수정하세요. 입주 후라면 전출 처리 → 면적 수정 → 재입주 처리 순서로 진행하세요.</p><h3 id="고지서-발송-시-sms가-전송되지-않아요" tabindex="-1">고지서 발송 시 SMS가 전송되지 않아요 <a class="header-anchor" href="#고지서-발송-시-sms가-전송되지-않아요" aria-label="Permalink to &quot;고지서 발송 시 SMS가 전송되지 않아요&quot;">​</a></h3><p><strong>원인</strong>: 발신번호 인증이 완료되지 않았거나 환경설정이 누락된 경우 <strong>해결</strong>: 발신번호 인증 절차(통신가입증명서 → 대리인신청서 → 전산업체 제출)가 완료되었는지 확인하세요. 완료 후에도 안 되면 전산업체에 문의하세요.</p><h3 id="결재-요청이-안-돼요" tabindex="-1">결재 요청이 안 돼요 <a class="header-anchor" href="#결재-요청이-안-돼요" aria-label="Permalink to &quot;결재 요청이 안 돼요&quot;">​</a></h3><p><strong>원인</strong>: 해당 장표의 결재라인이 등록되지 않은 경우 <strong>해결</strong>: 결재라인등록(DANG0051) 화면에서 해당 장표의 결재 경로를 등록하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/dang/dang-info.html">단지정보</a> - 단지코드·동호·단체·결재라인 등록</li><li><a href="/dang/dang-env.html">환경설정</a> - 검침·부과·고지서 환경 설정</li><li><a href="/dang/dang-table.html">조견표</a> - 관리비·주차비 단가 기준표</li><li><a href="/impo/basic.html">부과 기초정보</a> - 부과그룹·항목 설정 (초기 설정 이후)</li><li><a href="/pay/hr.html">인사관리</a> - 직원 정보 등록 (초기 설정 이후)</li><li><a href="/guide/scenarios/meter-reading.html">검침 처리</a> - 초기 설정 완료 후 첫 검침 업무</li></ul>`,127)])])}const u=a(e,[["render",o]]);export{b as __pageData,u as default};
